at::Tensor max_pooling_1d_custom_impl_npu(const at::Tensor& self,
                                          int64_t kernel_size,
                                          c10::optional<int64_t> stride_opt,
                                          int64_t padding,
                                          bool return_indices) {
    TORCH_CHECK(self.dim() == 3, "MaxPooling1dCustom expects input of shape (N, C, L)");
    int64_t stride = stride_opt.has_value() ? stride_opt.value() : kernel_size;
    TORCH_CHECK(!return_indices, "MaxPooling1dCustom: return_indices=True not supported");
    at::Tensor result = at::empty({self.size(0), self.size(1),
                                   (self.size(2) + 2 * padding - kernel_size) / stride + 1},
                                   self.options());
    EXEC_NPU_CMD(aclnnMaxPooling1dCustom, self, (int)kernel_size, (int)stride, (int)padding, result);
    return result;
